namespace Traxon.CryptoTrader.Application.Polymarket.Models;

public sealed record PolymarketMarket
{
    public string ConditionId       { get; init; } = string.Empty;
    public string Question          { get; init; } = string.Empty;
    public string YesTokenId        { get; init; } = string.Empty;
    public string NoTokenId         { get; init; } = string.Empty;
    public long   EndDateUtcSeconds { get; init; }   // Unix timestamp
    public bool   Active            { get; init; }
    public bool   Closed            { get; init; }
    public string UnderlyingAsset   { get; init; } = string.Empty;  // "BTC", "ETH" vb.
    public string Direction         { get; init; } = string.Empty;  // "Up" veya "Down"
    public string RelevantTokenId   => Direction == "Up" ? YesTokenId : NoTokenId;
    public DateTimeOffset EndDate   => DateTimeOffset.FromUnixTimeSeconds(EndDateUtcSeconds);
    public TimeSpan       TimeLeft  => EndDate - DateTimeOffset.UtcNow;
}
```

### 2b. PolymarketOrderBook.cs
```csharp
namespace Traxon.CryptoTrader.Application.Polymarket.Models;

public sealed record PolymarketOrderBook
{
    public string                       TokenId { get; init; } = string.Empty;
    public IReadOnlyList<PolymarketLevel> Bids  { get; init; } = [];
    public IReadOnlyList<PolymarketLevel> Asks  { get; init; } = [];

    public decimal BestBid  => Bids.Count > 0 ? Bids.Max(b => b.Price) : 0m;
    public decimal BestAsk  => Asks.Count > 0 ? Asks.Min(a => a.Price) : 1m;
    public decimal Midpoint => (BestBid + BestAsk) / 2m;
}

public sealed record PolymarketLevel(decimal Price, decimal Size);
```

